import React, { useState } from 'react';
import { Search, Package, ArrowLeft, CheckCircle, Loader2, ArrowRight, Sparkles } from 'lucide-react';
import { Button } from './Button';

type ServiceType = 'sourcing' | 'shipping' | null;
type FormStep = 'selection' | 'details' | 'success';

export const LeadForm: React.FC = () => {
  const [step, setStep] = useState<FormStep>('selection');
  const [service, setService] = useState<ServiceType>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    details: ''
  });

  const handleSelection = (selected: ServiceType) => {
    if (selected === 'sourcing') {
      window.location.href = 'typeformS+S.html';
      return;
    }
    setService(selected);
    setStep('details');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Simulate API call
    setTimeout(() => {
      setIsSubmitting(false);
      setStep('success');
    }, 1500);
  };

  const resetForm = () => {
    setStep('selection');
    setService(null);
    setFormData({ name: '', phone: '', details: '' });
  };

  return (
    <section id="start-now" className="py-24 px-4 bg-navy-900 text-white relative overflow-hidden min-h-[800px] flex items-center">
        {/* Background Gradients */}
        <div className="absolute top-0 left-0 w-96 h-96 bg-brand-orange/10 rounded-full blur-3xl -translate-x-1/2 -translate-y-1/2 pointer-events-none"></div>
        <div className="absolute bottom-0 right-0 w-96 h-96 bg-blue-600/10 rounded-full blur-3xl translate-x-1/2 translate-y-1/2 pointer-events-none"></div>

      <div className="max-w-5xl mx-auto relative z-10 w-full">

        {step === 'selection' && (
          <div className="animate-fadeIn">
            <div className="mb-16 text-center">
              <h2 className="text-3xl md:text-5xl font-black mb-6">
                جاهز للبدء؟ اختر مسارك الآن
              </h2>
              <p className="text-slate-300 text-xl max-w-2xl mx-auto">
                لا تضيع المزيد من الوقت في البحث العشوائي. انضم إلى مئات التجار الناجحين اليوم.
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 md:gap-10">
                {/* Option 1: Sourcing */}
                <button 
                    onClick={() => handleSelection('sourcing')}
                    className="w-full text-right group relative bg-navy-800/80 backdrop-blur-xl border border-white/10 hover:border-brand-orange/50 rounded-[2rem] p-8 md:p-12 transition-all duration-500 hover:-translate-y-2 hover:shadow-[0_20px_60px_-15px_rgba(249,115,22,0.2)] flex flex-col h-full overflow-hidden"
                >
                    <div className="absolute inset-0 bg-gradient-to-br from-brand-orange/5 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>

                    <div className="relative z-10 w-full">
                        <div className="flex justify-between items-start mb-6">
                             <div className="w-16 h-16 bg-gradient-to-br from-brand-orangeStart to-brand-orangeEnd rounded-2xl flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform">
                                <Search className="w-8 h-8 text-white" />
                            </div>
                            <div className="bg-brand-orange/10 text-brand-orange px-3 py-1 rounded-full text-xs font-bold border border-brand-orange/20">
                                الأكثر طلباً
                            </div>
                        </div>

                        <h3 className="text-2xl md:text-3xl font-bold text-white mb-3">أريد توريد منتج</h3>
                        <p className="text-slate-400 mb-8 leading-relaxed">
                            ليس لديك مورد؟ نحن نجد المصنع، نفحص الجودة، ونشحن لك البضاعة حتى باب منزلك.
                        </p>
                    </div>

                    <div className="mt-auto w-full relative z-10 bg-gradient-to-r from-brand-orangeStart to-brand-orangeEnd text-white font-bold py-4 rounded-xl text-center shadow-lg group-hover:shadow-orange-500/40 transition-all flex items-center justify-center gap-2">
                        ابدأ طلب التوريد
                        <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
                    </div>
                </button>

                {/* Option 2: Shipping */}
                <button 
                    onClick={() => handleSelection('shipping')}
                    className="w-full text-right group relative bg-white border border-slate-100 rounded-[2rem] p-8 md:p-12 transition-all duration-500 hover:-translate-y-2 hover:shadow-[0_20px_60px_-15px_rgba(37,99,235,0.2)] flex flex-col h-full overflow-hidden"
                >
                     <div className="absolute top-0 left-8 right-8 h-1 bg-blue-600 rounded-b-lg opacity-20 group-hover:opacity-100 transition-opacity"></div>

                    <div className="relative z-10 w-full">
                         <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center mb-6 shadow-sm border border-blue-100 group-hover:scale-110 transition-transform">
                            <Package className="w-8 h-8 text-blue-600" />
                        </div>
                        <h3 className="text-2xl md:text-3xl font-bold text-slate-900 mb-3">لدي سلعة جاهزة</h3>
                        <p className="text-slate-500 mb-8 leading-relaxed">
                            اشتريت البضاعة بالفعل؟ احصل على عنوان مخزننا في الصين، ونحن نتكفل بالشحن والتخليص.
                        </p>
                    </div>

                    <div className="mt-auto w-full relative z-10 bg-slate-800 text-white font-bold py-4 rounded-xl text-center shadow-lg group-hover:bg-slate-900 transition-all flex items-center justify-center gap-2">
