                    </div>
                </button>
            </div>

            <p className="mt-12 text-slate-500 text-sm text-center">
                هذه الخدمة مخصصة للتجار والشركات فقط.
            </p>
          </div>
        )}

        {step === 'details' && (
          <div className="max-w-2xl mx-auto bg-white rounded-3xl p-8 md:p-12 shadow-2xl animate-fadeIn text-slate-900">
            <button 
              onClick={() => setStep('selection')}
              className="flex items-center text-slate-400 hover:text-slate-600 mb-6 font-bold text-sm transition-colors"
            >
              <ArrowRight className="w-4 h-4 ml-1" />
              تغيير الخدمة
            </button>

            <div className="flex items-center gap-3 mb-8">
              <div className={`p-3 rounded-xl ${service === 'sourcing' ? 'bg-orange-100 text-brand-orange' : 'bg-blue-100 text-blue-600'}`}>
                {service === 'sourcing' ? <Search className="w-8 h-8" /> : <Package className="w-8 h-8" />}
              </div>
              <div>
                <h3 className="text-2xl font-bold text-navy-900">
                  {service === 'sourcing' ? 'طلب توريد (Sourcing)' : 'طلب شحن (Shipping)'}
                </h3>
                <p className="text-slate-500 text-sm">أدخل بياناتك ليتواصل معك فريقنا المختص.</p>
              </div>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-sm font-bold text-navy-900 mb-2">الاسم الكامل</label>
                <input 
                  required
                  type="text" 
                  value={formData.name}
                  onChange={(e) => setFormData({...formData, name: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-4 focus:ring-2 focus:ring-brand-orange focus:border-transparent outline-none transition-all"
